

    const statuesData = [
        {
            id: "tut",
            name: "الملك توت عنخ آمون",
            imgUrl: "data:image/jpeg;base64,",
            imgAlt: "قناع الملك توت عنخ آمون الذهبي",
            info: "الملك توت عنخ آمون فرعون شاب ذهبي. حكم مصر منذ أكثر من 3300 سنة. اشتهر بقناعه الذهبي الرائع من أعظم كنوز العالم.",
            questions: [
                {
                    text: "في المتحف المصري، ماذا يجب أن تفعل عندما تشاهد تمثال توت عنخ آمون؟",
                    options: ["ألمسه لأنه جميل", "أحترم المكان وألتقط صوراً بدون فلاش", "أصرخ وأجري حوله"],
                    correct: 1,
                    explanation: "أحسنت يا بطل. يجب احترام الآثار وعدم لمسها."
                },
                {
                    text: "هل يجوز أن نرمي أي شيء على الأرض في قاعة الملك توت؟",
                    options: ["نعم عادي", "لا أبداً، نحافظ على النظافة", "فقط إذا كان خفيفاً"],
                    correct: 1,
                    explanation: "إجابة ممتازة. ممنوع رمي أي شيء على الأرض في المتحف."
                }
            ]
        },
        {
            id: "ramses",
            name: "الملك رمسيس الثاني",
            imgUrl: "data:image/jpeg;base64,",
            imgAlt: "تمثال الملك رمسيس الثاني",
            info: "الملك رمسيس الثاني هو أعظم فراعنة مصر. حكم مصر ستة وستين سنة. عُرف باسم رمسيس الكبير وباني معابد أبو سمبل.",
            questions: [
                {
                    text: "أثناء جولة المرشدة أمام تمثال رمسيس، ماذا نفعل؟",
                    options: ["نتجول وحدنا", "نبقى قريبين من المرشدة ونستمع لها", "نلعب وندفع بعضنا"],
                    correct: 1,
                    explanation: "صحيح. لا نبتعد عن المرشدة لنستمع ونحافظ على سلامتنا."
                },
                {
                    text: "إذا رأيت طفلاً يدفع آخر أمام تمثال رمسيس، ماذا تفعل؟",
                    options: ["أدفعه أيضاً", "أخبر المرشدة ميرنا", "أتجاهل الأمر"],
                    correct: 1,
                    explanation: "أحسنت. ممنوع دفع الناس، نكون مهذبين ونساعد بعضنا."
                }
            ]
        }
    ];

    let rewardsEarned = { tut: false, ramses: false, anubis: false };
    let correctAnswersMap = { tut: 0, ramses: 0 };
    let answeredStatus = {};

    const museumSection = document.getElementById('museumSection');
    const rewardStarsSpan = document.getElementById('rewardStars');
    const prizeIcons = document.querySelectorAll('.prize-icon');
    const globalMsgDiv = document.getElementById('globalMessage');
    const repeatRulesBtn = document.getElementById('repeatRulesBtn');
    const voiceIndicator = document.getElementById('voiceIndicator');

    const rulesTexts = [
        "ممنوع رمي أي حاجة على الأرض، نحافظ على نظافة المتحف",
        "ممنوع لمس التماثيل الأثرية نهائياً، ننظر بأعيننا فقط",
        "ممنوع دفع الناس أو الزحام، نكون أطفال مهذبين",
        "ممنوع نبتعد عن المرشدة، نبقى مع المجموعة طول الوقت"
    ];

    // ==============================================
    // ده الجزء اللي اتعمل فيه التعديل عشان المرشدة تتكلم عربي صح
    // ==============================================
    let currentUtterance = null;

    function speakMessage(message) {
        if (!window.speechSynthesis) {
            console.log("المتصفح لا يدعم الصوت");
            return;
        }
        
        try {
            // إيقاف أي كلام سابق
            if (currentUtterance) {
                window.speechSynthesis.cancel();
            }
            
            const utterance = new SpeechSynthesisUtterance(message);
            utterance.lang = 'ar-EG';
            utterance.rate = 0.85;
            utterance.pitch = 1.1;
            utterance.volume = 1;
            
            // البحث عن صوت عربي
            const voices = window.speechSynthesis.getVoices();
            let arabicVoice = null;
            
            for (let voice of voices) {
                if (voice.lang === 'ar-EG') {
                    arabicVoice = voice;
                    break;
                }
            }
            if (!arabicVoice) {
                for (let voice of voices) {
                    if (voice.lang === 'ar-SA' || voice.lang === 'ar') {
                        arabicVoice = voice;
                        break;
                    }
                }
            }
            
            if (arabicVoice) {
                utterance.voice = arabicVoice;
            }
            
            currentUtterance = utterance;
            
            if (voiceIndicator) {
                voiceIndicator.classList.add('speaking');
                voiceIndicator.innerHTML = '🔊 تتحدث...';
            }
            
            utterance.onend = () => {
                currentUtterance = null;
                if (voiceIndicator) {
                    voiceIndicator.classList.remove('speaking');
                    voiceIndicator.innerHTML = '🔊 تتحدث عربي';
                }
            };
            
            utterance.onerror = () => {
                currentUtterance = null;
                if (voiceIndicator) {
                    voiceIndicator.classList.remove('speaking');
                    voiceIndicator.innerHTML = '🔊 تتحدث عربي';
                }
            };
            
            window.speechSynthesis.speak(utterance);
        } catch(e) {
            console.log("خطأ في النطق:", e);
        }
    }

    function speakAllRules() {
        let intro = "مرحباً يا أطفال. أنا المرشدة ميرنا. هذه هي تعليمات المتحف المصري: ";
        let allRules = rulesTexts.join(". ");
        speakMessage(intro + allRules);
    }
    // ==============================================
    // انتهى الجزء اللي اتعمل فيه التعديل
    // ==============================================

    function renderRules() {
        document.getElementById('rulesList').innerHTML = rulesTexts.map(r => `
            <div class="rule-card"><span>📜</span> ${r}</div>
        `).join('');
    }

    function updateRewardsUI() {
        let count = (rewardsEarned.tut?1:0) + (rewardsEarned.ramses?1:0) + (rewardsEarned.anubis?1:0);
        rewardStarsSpan.innerText = count + " 🎁";
        
        prizeIcons.forEach(icon => {
            const type = icon.getAttribute('data-prize');
            if(rewardsEarned[type]) {
                icon.classList.add('collected');
            } else {
                icon.classList.remove('collected');
            }
        });
        
        if(count >= 3) {
            globalMsgDiv.innerHTML = "🎉🎉🎉 مبروك يا بطل. حصلت على كل التماثيل الثلاثة. أنت طفل مثالي 🎉🎉🎉";
        } else if(count > 0) {
            globalMsgDiv.innerHTML = `🎁 أحسنت. ربحت ${count} تمثال. أكمل الأسئلة لتربح الباقي 🎁`;
        } else {
            globalMsgDiv.innerHTML = "✨ جاوب على الأسئلة بشكل صحيح لتربح تماثيل رائعة من المتحف المصري ✨";
        }
    }

    function checkAndGrantReward(statueId) {
        if(statueId === 'tut' && !rewardsEarned.tut && correctAnswersMap.tut >= 2) {
            rewardsEarned.tut = true;
            speakMessage("أحسنت يا عبقري. لقد ربحت تمثال الملك توت عنخ آمون الذهبي");
            updateRewardsUI();
            checkBonusAnubis();
        }
        else if(statueId === 'ramses' && !rewardsEarned.ramses && correctAnswersMap.ramses >= 2) {
            rewardsEarned.ramses = true;
            speakMessage("رائع جداً. لقد ربحت تمثال الملك رمسيس الثاني العظيم");
            updateRewardsUI();
            checkBonusAnubis();
        }
    }
    
    function checkBonusAnubis() {
        if(rewardsEarned.tut && rewardsEarned.ramses && !rewardsEarned.anubis) {
            rewardsEarned.anubis = true;
            speakMessage("مدهش. حصلت على التمثالين معاً، لك جائزة خاصة، تمثال أنوبيس");
            updateRewardsUI();
        }
    }

    function renderStatues() {
        museumSection.innerHTML = '';
        statuesData.forEach(statue => {
            const card = document.createElement('div');
            card.className = 'statue-card';
            const imgClass = statue.id === 'tut' ? 'tut-img' : 'ramses-img';
            card.innerHTML = `
                <div class="statue-img-container">
                    <img class="statue-img ${imgClass}" src="${statue.imgUrl}" alt="${statue.imgAlt}" loading="lazy" 
                         onerror="this.src='https://placehold.co/500x500/d4af37/a45117?text=${encodeURIComponent(statue.name)}'">
                </div>
                <div class="statue-name">${statue.name}</div>
                <div class="statue-info">📖 ${statue.info}</div>
                <div class="quiz-area">
                    <div style="font-weight:bold; margin-bottom:12px;">📝 أسئلة من المرشدة ميرنا</div>
                    <div id="q-container-${statue.id}"></div>
                </div>
            `;
            museumSection.appendChild(card);
            
            const qContainer = document.getElementById(`q-container-${statue.id}`);
            statue.questions.forEach((q, idx) => {
                const qDiv = document.createElement('div');
                qDiv.className = 'question';
                qDiv.innerHTML = `
                    <p>❓ ${q.text}</p>
                    <div class="options" id="opts-${statue.id}-${idx}"></div>
                    <div class="feedback" id="fb-${statue.id}-${idx}"></div>
                `;
                qContainer.appendChild(qDiv);
                
                const optsDiv = qDiv.querySelector('.options');
                q.options.forEach((opt, optIdx) => {
                    const btn = document.createElement('button');
                    btn.className = 'option-btn';
                    btn.textContent = opt;
                    btn.onclick = () => handleAnswer(statue.id, idx, optIdx, q.correct, q.explanation);
                    optsDiv.appendChild(btn);
                });
            });
        });
    }

    function handleAnswer(statueId, qIdx, selected, correct, explanation) {
        const fb = document.getElementById(`fb-${statueId}-${qIdx}`);
        const key = `${statueId}_${qIdx}`;
        
        if(answeredStatus[key]) {
            speakMessage("أجبت على هذا السؤال من قبل يا بطل");
            fb.innerHTML = "✅ أجبت على هذا السؤال من قبل";
            return;
        }
        
        if(selected === correct) {
            fb.innerHTML = `✅ صحيح. ${explanation}`;
            fb.style.color = "#2d6a4f";
            fb.style.background = "#e8f5e9";
            speakMessage(`إجابة صحيحة. ${explanation}`);
            correctAnswersMap[statueId] = (correctAnswersMap[statueId] || 0) + 1;
            answeredStatus[key] = true;
            
            const optsDiv = document.getElementById(`opts-${statueId}-${qIdx}`);
            if(optsDiv) {
                optsDiv.querySelectorAll('.option-btn').forEach(btn => btn.disabled = true);
            }
            checkAndGrantReward(statueId);
        } else {
            const correctText = correct === 0 ? "الأول" : (correct === 1 ? "الثاني" : "الثالث");
            fb.innerHTML = `❌ خطأ. الإجابة الصحيحة هي الخيار ${correctText}. ${explanation} حاول مرة أخرى`;
            fb.style.color = "#c0392b";
            fb.style.background = "#fdf0f0";
            speakMessage(`للأسف خطأ. ${explanation} حاول مرة أخرى`);
        }
        updateRewardsUI();
    }

    // تحميل الأصوات
    if (window.speechSynthesis) {
        window.speechSynthesis.getVoices();
        if (window.speechSynthesis.onvoiceschanged !== undefined) {
            window.speechSynthesis.onvoiceschanged = () => {
                window.speechSynthesis.getVoices();
            };
        }
    }
    
    setTimeout(() => {
        speakMessage("السلام عليكم يا أطفال. أنا المرشدة ميرنا. أهلاً بكم في المتحف المصري");
        setTimeout(() => speakAllRules(), 3000);
    }, 1000);
    
    repeatRulesBtn.onclick = () => speakAllRules();
    
    renderRules();
    renderStatues();
    updateRewardsUI();
